from kafka import KafkaConsumer
import json

def process_transaction(transaction):
    # Implement the business logic here based on transaction type
    transaction_type = transaction.get('type')
    if transaction_type == 'credit':
        handle_credit(transaction)
    elif transaction_type == 'debit':
        handle_debit(transaction)
    else:
        handle_unknown(transaction)

def handle_credit(transaction):
    # Business logic for processing a credit transaction
    print(f"Processing credit transaction: {transaction}")

def handle_debit(transaction):
    # Business logic for processing a debit transaction
    print(f"Processing debit transaction: {transaction}")

def handle_unknown(transaction):
    # Handle unknown transaction type
    print(f"Unknown transaction type: {transaction}")

consumer = KafkaConsumer(
    'financial_transactions',
    bootstrap_servers=['localhost:9092'],
    value_deserializer=lambda m: json.loads(m.decode('utf-8')),
    group_id='transaction_processor'
)

